return items.map(item => {
  const data = item.json;

  let categoryOutput = null;

  if (Array.isArray(data.categories)) {
    categoryOutput = data.categories;   // return as array
  } else if (typeof data.categories === "string") {
    categoryOutput = data.categories;   // return as string
  }

  return {
    category: categoryOutput,
    competitor: data.brand || null,
    productName: data.title || null,

    price: data.buybox_price ||
           data.final_price ||
           data.initial_price ||
           null,

    variants: data.variations
      ? data.variations.map(v => ({
          name: v.name || null,
          asin: v.asin || null,
          price: v.price || null,
          currency: v.currency || null
        }))
      : null,

    availability: data.availability || null
  };
});

