  "cluster": "",
  "missingVariants": [],
  "bundleOpportunity": "",
  "positioningGap": ""
}

parameters.jsCode:
return items.map(item => {

  const data = item.json.output; // ✅ correct path
  let score = 0;

  // Positioning gap scoring
  if (data.positioningGap) {
    const gapText = data.positioningGap.toLowerCase();

    if (
      gapText.includes("premium") ||
      gapText.includes("high") ||
      gapText.includes("extreme")
    ) {
      score += 40;
    } else if (gapText.length > 0) {
      score += 25;
    }
  }

  // Missing variants scoring
  if (Array.isArray(data.missingVariants) && data.missingVariants.length > 0) {
    score += 30;
  }

  // Bundle opportunity scoring
  if (data.bundleOpportunity && data.bundleOpportunity.length > 0) {
    score += 30;
  }

  return {
    json: {
      ...data,
      pricingGapScore: score
    }
  };
});
